"use client";

import React, { createContext, useContext, useEffect, useState } from 'react';
import { User } from '@/types';
import { MockDataService } from '@/services/MockDataService';

interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  login: (username: string, password: string) => Promise<boolean>;
  logout: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Check for persisted session
    const storedUser = localStorage.getItem('dp_auth');
    if (storedUser) {
      setUser(JSON.parse(storedUser));
    }
    MockDataService.initializeData();
    setIsLoading(false);
  }, []);

  const login = async (username: string, password: string): Promise<boolean> => {
    setIsLoading(true);
    // Simulate network delay
    await new Promise(resolve => setTimeout(resolve, 800));

    // Simple password validation (in real app, use hashing and proper auth)
    // For PoC: 'demo123' for dentista, 'admin123' for admin
    let isValid = false;
    if (username === 'dentista' && password === 'demo123') isValid = true;
    if (username === 'admin' && password === 'admin123') isValid = true;

    if (isValid) {
      const authenticatedUser = MockDataService.authenticate(username);
      if (authenticatedUser) {
        setUser(authenticatedUser);
        localStorage.setItem('dp_auth', JSON.stringify(authenticatedUser));
        setIsLoading(false);
        return true;
      }
    }

    setIsLoading(false);
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('dp_auth');
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated: !!user,
        isLoading,
        login,
        logout,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};
