"use client";

import React, { createContext, useContext, useEffect, useState, useCallback } from 'react';
import { Order, OrderStatus } from '@/types';
import { MockDataService } from '@/services/MockDataService';
import { useAuth } from './AuthContext';

interface OrderFilters {
  status?: OrderStatus;
  searchTerm?: string;
}

interface OrderContextType {
  orders: Order[];
  loading: boolean;
  error: string | null;
  filters: OrderFilters;
  setFilters: React.Dispatch<React.SetStateAction<OrderFilters>>;
  addOrder: (orderData: Omit<Order, 'id' | 'createdAt' | 'dentistName' | 'dentistId'>) => Promise<void>;
  updateOrderStatus: (orderId: string, status: OrderStatus) => Promise<void>;
  refreshOrders: () => void;
}

const OrderContext = createContext<OrderContextType | undefined>(undefined);

export const OrderProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [filters, setFilters] = useState<OrderFilters>({});

  const fetchOrders = useCallback(() => {
    if (!user) return;
    
    setLoading(true);
    try {
      const data = MockDataService.getOrders(user.role, user.id);
      
      let filteredData = data;
      
      if (filters.status) {
        filteredData = filteredData.filter(o => o.status === filters.status);
      }
      
      if (filters.searchTerm) {
        const term = filters.searchTerm.toLowerCase();
        filteredData = filteredData.filter(o => 
          o.patientName.toLowerCase().includes(term) || 
          o.id.toLowerCase().includes(term)
        );
      }
      
      setOrders(filteredData);
      setError(null);
    } catch (err) {
      setError('Error al cargar pedidos');
    } finally {
      setLoading(false);
    }
  }, [user, filters]);

  useEffect(() => {
    fetchOrders();
  }, [fetchOrders]);

  const addOrder = async (orderData: Omit<Order, 'id' | 'createdAt' | 'dentistName' | 'dentistId'>) => {
    if (!user) return;
    
    setLoading(true);
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 500));
    
    try {
      MockDataService.createOrder(orderData as any, user);
      fetchOrders();
    } catch (err) {
      setError('Error al crear pedido');
    } finally {
      setLoading(false);
    }
  };

  const updateOrderStatus = async (orderId: string, status: OrderStatus) => {
    setLoading(true);
    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 300));
    
    try {
      MockDataService.updateOrderStatus(orderId, status);
      fetchOrders();
    } catch (err) {
      setError('Error al actualizar estado');
    } finally {
      setLoading(false);
    }
  };

  return (
    <OrderContext.Provider
      value={{
        orders,
        loading,
        error,
        filters,
        setFilters,
        addOrder,
        updateOrderStatus,
        refreshOrders: fetchOrders,
      }}
    >
      {children}
    </OrderContext.Provider>
  );
};

export const useOrders = () => {
  const context = useContext(OrderContext);
  if (context === undefined) {
    throw new Error('useOrders must be used within an OrderProvider');
  }
  return context;
};
